const stdout = String($json.stdout ?? '').trim();
if (!stdout) {
  return [];
}

let parsed;
try {
  parsed = JSON.parse(stdout);
} catch (error) {
  throw new Error('Fetch node did not return JSON: ' + error.message);
}

if (Array.isArray(parsed.errors) && parsed.errors.length > 0) {
  throw new Error(parsed.errors.map((item) => item.error).join('; '));
}

return (parsed.emails ?? []).map((email) => ({
  json: {
    ...email,
    sourceFlow: 'bulk',
    runMode: 'apply_labels',
    labelPrefix: email.labelPrefix || 'Labels',
    stateLabel: email.stateLabel || 'Classified',
  },
}));

function parseSender(value) {
  if (Array.isArray(value)) return parseSender(value[0]);
  if (value && typeof value === 'object') {
    const email = value.email || value.address || value.mail || '';
    const name = value.name || value.displayName || '';
    const header = value.value || value.text || (name || email ? `${name} <${email}>` : '');
    return { header, name, email };
  }

  const header = String(value || '');
  const match = header.match(/^(.*?)\s*<([^>]+)>$/);
  if (match) {
    return { header, name: match[1].replace(/^"|"$/g, '').trim(), email: match[2].trim() };
  }
  return { header, name: '', email: header.includes('@') ? header.trim() : '' };
}

const sender = parseSender($json.from ?? $json.sender ?? $json.sender_email ?? $json.senderEmail);
const subject = String($json.subject ?? $json.email_subject ?? $json.emailSubject ?? '');
const body = String($json.text ?? $json.textPlain ?? $json.body ?? $json.email_body ?? $json.emailBody ?? '');

return [{
  json: {
    ...$json,
    sourceFlow: 'trigger',
    runMode: 'apply_labels',
    uid: String($json.uid ?? $json.imapUid ?? $json.messageUid ?? ''),
    message_id: String($json.messageId ?? $json.message_id ?? $json['message-id'] ?? ''),
    from: sender.header,
    sender_name: sender.name,
    sender_email: sender.email,
    subject,
    email_subject: subject,
    body_preview: body.slice(0, 4000),
    email_body: body.slice(0, 4000),
    sourceMailbox: 'INBOX',
    labelPrefix: 'Labels',
    stateLabel: 'Classified',
    dryRun: false,
    imapHost: '192.168.3.200',
    imapPort: 1143,
    imapSsl: false,
    imapStartTls: true,
  },
}];

const source = $('Build classification prompt').item.json;
const allowed = ["Invoice","Purchase","Bill","Payment","Marketing","Cold email","Important","Awaiting reply","Travel","Ticket","Infrastructure","Hustle"];

function parseAiOutput(value) {
  if (value && typeof value === 'object' && 'output' in value && Object.keys(value).length === 1) {
    return parseAiOutput(value.output);
  }
  if (typeof value === 'string') {
    return JSON.parse(value);
  }
  return value;
}

let parsed;
try {
  parsed = parseAiOutput($json.output ?? $json);
} catch (error) {
  parsed = { labels: [{ label: 'uncertain', confidence: 0 }], reason: 'format violation or instruction conflict' };
}

const accepted = [];
for (const item of Array.isArray(parsed?.labels) ? parsed.labels : []) {
  const label = item?.label;
  const confidence = Math.max(0, Math.min(1, Number(item?.confidence ?? 0)));
  if (!allowed.includes(label) || confidence < 0.75) continue;
  if (!accepted.some((existing) => existing.label === label)) {
    accepted.push({ label, confidence });
  }
}

const reason = String(parsed?.reason ?? (accepted.length ? 'Classifier returned matching labels' : 'No label reached confidence threshold')).slice(0, 240);
const labelPrefix = source.labelPrefix || 'Labels';
const stateLabel = source.stateLabel || 'Classified';
const labelMailboxes = accepted.map((item) => `${labelPrefix}/${item.label}`);
const stateMailbox = `${labelPrefix}/${stateLabel}`;
const targetMailboxes = [...labelMailboxes];
if (!targetMailboxes.includes(stateMailbox)) targetMailboxes.push(stateMailbox);

return [{
  json: {
    ...source,
    runMode: 'apply_labels',
    classification: {
      labels: accepted.length ? accepted : [{ label: 'uncertain', confidence: Number(parsed?.labels?.[0]?.confidence ?? 0) }],
      reason,
    },
    labels: accepted,
    labelMailboxes,
    stateMailbox,
    targetMailboxes,
  },
}];
